CREATE TABLE IF NOT EXISTS weather_forecasts (id uuid PRIMARY KEY, asset_id uuid NOT NULL REFERENCES offshore_assets(id) ON DELETE CASCADE, forecast_at timestamptz NOT NULL DEFAULT now(), valid_at timestamptz NOT NULL, wind_speed double precision NOT NULL, wave_height double precision NOT NULL, visibility double precision, source text NOT NULL, confidence double precision NOT NULL DEFAULT 0.8 CHECK (confidence BETWEEN 0 AND 1), metadata jsonb NOT NULL DEFAULT '{}');
CREATE INDEX IF NOT EXISTS weather_forecasts_asset_valid_idx ON weather_forecasts (asset_id, valid_at);
CREATE TABLE IF NOT EXISTS operational_windows (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, asset_id uuid NOT NULL REFERENCES offshore_assets(id) ON DELETE CASCADE, name text NOT NULL, type text NOT NULL, start_at timestamptz NOT NULL, end_at timestamptz NOT NULL, constraints jsonb NOT NULL DEFAULT '{}', status text NOT NULL CHECK (status IN ('OPEN','CLOSED','CONSTRAINED')) DEFAULT 'OPEN', created_at timestamptz NOT NULL DEFAULT now(), CHECK (end_at > start_at));
CREATE INDEX IF NOT EXISTS operational_windows_asset_time_idx ON operational_windows (asset_id,start_at,end_at);
